      effectiveContext = {
        ...effectiveContext,
        project_id: effectiveProjectId,
        current_stage: typeof effectiveContext.current_stage === 'string'
          ? effectiveContext.current_stage
          : (projectContext.currentStage || 'stage_01_brainstorm'),
      };
