        <pre style="background: #fef2f2; border: 1px solid #fecaca; border-radius: 6px; padding: 12px; font-size: 12px; line-height: 1.5; white-space: pre-wrap; word-break: break-all; overflow-x: auto; color: #dc2626;">${escapedError}</pre>
        <button id="__ask_ai_btn" style="display:inline-block;margin-top:8px;padding:8px 16px;background:#0ea5e9;color:#fff;border:none;border-radius:8px;cursor:pointer;font-size:13px;font-weight:500;" onclick="(function(){window.parent.postMessage({type:'code-error',msg:${JSON.stringify(result.error)}},'*');this.textContent='宸插彂閫佺粰AI...';this.disabled=true;this.style.background='#94a3b8';})()">Ask AI to fix this error</button>
      </div>` : ''}
      ${!result.output && !hasError ? '<div style="font-size:12px;color:#9ca3af;padding:8px 0;">(鏃犺緭鍑?</div>' : ''}
    </div>
  `;
}

function buildErrorHtml(message: string): string {
  return `
    <div style="font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; padding: 16px; text-align: center;">
      <div style="padding: 16px; background: #fef2f2; border: 1px solid #fecaca; border-radius: 8px; color: #dc2626; font-size: 14px;">
        鈿?${message}
      </div>
    </div>
  `;
}

export function Create() {
  const { stream } = useStreamingChat();
