                  <div className="text-[10px] text-gray-400 truncate">{entry.desc}</div>
                </div>
              </button>
            ))}
          </div>
        </Card>

        <Card className="p-0 overflow-hidden border-amber-100 bg-gradient-to-b from-amber-50 to-white">
