  const handleUpgradeToStandard = async () => {
    if (!project?.id || !confirm('纭畾瑕佸皢杞婚噺椤圭洰鍗囩骇涓烘爣鍑嗙爺瀛﹂」鐩悧锛熷崌绾у悗鍙娇鐢ㄥ畬鏁寸殑 9 闃舵鐮旂┒娴佺▼銆?)) return;
