            <div className="flex-1 min-w-0">
              <p className="text-sm font-medium text-teal-800">
                AI 鎻愬埌浜嗘枃浠躲€?span className="font-mono text-teal-900">{referredFile}</span>銆峔n              </p>
              <p className="text-xs text-teal-600 mt-1">
                {workspaceFilename && (
