// 鎴愬氨鍗＄墖鍒涘缓缁勪欢
function ProjectAchievement({
  project,
  onBack,
  onCreated,
}: {
  project: Project;
  onBack: () => void;
  onCreated: (achievement: AchievementCard) => void;
}) {
  const [title, setTitle] = useState(project.name);
  const [oneLiner, setOneLiner] = useState(project.description || '');
  const [problemSolved, setProblemSolved] = useState('');
  const [methodUsed, setMethodUsed] = useState('');
  const [reflection, setReflection] = useState('');
  const [tags, setTags] = useState<string[]>(project.tech_stack || []);
  const [newTag, setNewTag] = useState('');
  const [loading, setLoading] = useState(false);

  const handleAddTag = () => {
    if (newTag.trim() && !tags.includes(newTag.trim())) {
      setTags([...tags, newTag.trim()]);
      setNewTag('');
    }
  };

  const handleRemoveTag = (tag: string) => {
    setTags(tags.filter(t => t !== tag));
  };

  const handleCreate = async () => {
    try {
      setLoading(true);
      const response = await achievementCardsApi.create(project.id, {
        title,
        one_liner: oneLiner,
        problem_solved: problemSolved,
        method_used: methodUsed,
        screenshots: [],
        reflection,
        capability_tags: tags,
        project_mode: project.mode,
      });
      if (response.data) {
        onCreated(response.data);
      }
    } catch (err: any) {
      alert('鍒涘缓澶辫触锛? + err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="max-w-3xl mx-auto px-4">
        <Button variant="secondary" className="mb-6" onClick={onBack}>
          <ArrowLeft className="h-4 w-4 mr-2" />
          杩斿洖椤圭洰
        </Button>

        <Card>
          <CardHeader>
            <CardTitle>鐢熸垚鎴愭灉妗ｆ鍗?/CardTitle>
            <p className="text-gray-600 text-sm">濉啓淇℃伅锛岀敓鎴愪綘鐨勯」鐩垚鏋滄。妗堝崱</p>
          </CardHeader>
          <CardContent className="space-y-6">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">椤圭洰鍚嶇О</label>
              <input
                type="text"
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-transparent"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">涓€鍙ヨ瘽浠嬬粛</label>
              <textarea
                value={oneLiner}
                onChange={(e) => setOneLiner(e.target.value)}
                className="w-full h-24 px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-transparent"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">鎴戣В鍐充簡浠€涔堥棶棰?/label>
              <textarea
                value={problemSolved}
                onChange={(e) => setProblemSolved(e.target.value)}
                placeholder="鎻忚堪浣犳渶缁堝畬鎴愪簡浠€涔?.."
                className="w-full h-32 px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-transparent"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">鎴戠敤浜嗕粈涔堟柟娉?/label>
              <textarea
                value={methodUsed}
                onChange={(e) => setMethodUsed(e.target.value)}
                placeholder="鎻忚堪浣犻噰鐢ㄧ殑鏂规硶鍜屽疄鐜版€濊矾..."
                className="w-full h-32 px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-transparent"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">鎴戠殑鍙嶆€?/label>
              <textarea
                value={reflection}
                onChange={(e) => setReflection(e.target.value)}
                placeholder="杩欎釜椤圭洰涓綘瀛﹀埌鐨勫叧閿偣鍜屾敼杩涙兂娉?.."
                className="w-full h-24 px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-transparent"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">鏍囩</label>
              <div className="flex flex-wrap gap-2 mb-2">
                {tags.map((tag, idx) => (
                  <Badge key={idx} variant="secondary" className="flex items-center gap-1">
                    {tag}
                    <button onClick={() => handleRemoveTag(tag)} className="ml-1 hover:text-red-500">脳</button>
                  </Badge>
                ))}
              </div>
              <div className="flex gap-2">
                <input
                  type="text"
                  value={newTag}
                  onChange={(e) => setNewTag(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && (e.preventDefault(), handleAddTag())}
                  placeholder="娣诲姞鏍囩..."
                  className="flex-1 px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-transparent"
