                onClick={handleCreate}
                disabled={loading || !title || !oneLiner || !problemSolved || !methodUsed || !reflection}
              >
                {loading ? '鍒涘缓涓?..' : '鐢熸垚妗ｆ鍗?}
              </Button>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

