import { useEffect, useMemo, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Eye, Plus, Trophy } from 'lucide-react';
import { Card, CardContent } from '../components/ui/Card';
import { Button } from '../components/ui/Button';
import { Badge } from '../components/ui/Badge';
import { projectsApi } from '../services/api';
import { Project } from '../types';

export function Research() {
  const [activeTab, setActiveTab] = useState<'in_progress' | 'completed'>('in_progress');
  const [items, setItems] = useState<Project[]>([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  const loadProjects = async () => {
    setLoading(true);
    try {
      const res = await projectsApi.list({ page: 1, page_size: 200 });
      setItems(res.data?.items ?? []);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    void loadProjects();
  }, []);

  const displayed = useMemo(() => {
    const isDone = (stage?: string) => stage === 'stage_08_evaluate';
    if (activeTab === 'completed') {
      return items.filter((item) => isDone(item.current_stage));
    }
    return items.filter((item) => !isDone(item.current_stage));
  }, [activeTab, items]);

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-bold text-gray-800">鎴戠殑椤圭洰</h1>
        <Button onClick={() => navigate('/create')}>
          <Plus className="w-4 h-4 mr-2" />
          鏂板缓椤圭洰
        </Button>
      </div>

      <div className="flex space-x-1 border-b border-gray-200">
        <button
          onClick={() => setActiveTab('in_progress')}
          className={`px-4 py-2 text-sm font-medium border-b-2 transition-colors ${
            activeTab === 'in_progress'
              ? 'border-primary-500 text-primary-600'
              : 'border-transparent text-gray-500 hover:text-gray-700'
          }`}
        >
          杩涜涓璡n        </button>
        <button
          onClick={() => setActiveTab('completed')}
          className={`px-4 py-2 text-sm font-medium border-b-2 transition-colors ${
            activeTab === 'completed'
              ? 'border-primary-500 text-primary-600'
              : 'border-transparent text-gray-500 hover:text-gray-700'
          }`}
        >
          宸插畬鎴怽n        </button>
      </div>

      {loading ? (
        <div className="text-sm text-gray-500">鍔犺浇涓?..</div>
      ) : (
        <ProjectList items={displayed} completed={activeTab === 'completed'} />
      )}
    </div>
  );
}

function ProjectList({ items, completed }: { items: Project[]; completed: boolean }) {
  if (items.length === 0) {
    return <div className="text-sm text-gray-500">鏆傛棤椤圭洰</div>;
  }
  return <div className="space-y-4">{items.map((item) => <ProjectCard key={item.id} item={item} completed={completed} />)}</div>;
}

interface ProjectCardProps {
  item: Project;
  completed: boolean;
}

function getProgressByStage(stage?: string): number {
  const stages = [
    'stage_00_bootstrap',
    'stage_01_brainstorm',
    'stage_02_brief',
    'stage_03_constraints',
    'stage_04_track',
    'stage_05_design',
    'stage_06_step_plan',
    'stage_07_execute',
    'stage_08_evaluate',
  ];
  const index = Math.max(stages.indexOf(stage ?? ''), 0);
  return Math.round(((index + 1) / stages.length) * 100);
}

function ProjectCard({ item, completed }: ProjectCardProps) {
  const navigate = useNavigate();
  const progress = completed ? 100 : getProgressByStage(item.current_stage);

  const handleContinue = async () => {
    try {
      const workspaceRes = await projectsApi.getWorkspace(item.id);
      const restoreData: Record<string, unknown> = {
        projectId: item.id,
        projectName: item.name,
        mode: item.mode,
        currentStage: workspaceRes.data?.progress.current_stage || item.current_stage,
      };
      if (workspaceRes.data?.workspace) {
        restoreData.code = workspaceRes.data.workspace.code;
        restoreData.language = workspaceRes.data.workspace.language || 'python';
        restoreData.messages = workspaceRes.data.workspace.chat_messages || [];
      }
      sessionStorage.setItem('finestem_restore_project', JSON.stringify(restoreData));
      navigate('/create');
    } catch (error) {
      console.error('[research:continue] 鎭㈠椤圭洰澶辫触:', error);
      navigate(`/research/projects/${item.id}`);
    }
  };

  return (
    <Card hoverable>
      <CardContent className="p-6">
        <div className="flex items-start justify-between">
          <div className="flex-1">
            <div className="flex items-center gap-3 mb-2">
              <h3 className="text-lg font-semibold text-gray-800">
                {item.name}
              </h3>
              <Badge variant={completed ? 'success' : 'primary'}>
                {completed ? '宸插畬鎴? : item.mode === 'standard' ? '鏍囧噯鐮斿' : '杞婚」鐩?}
              </Badge>
            </div>
            <p className="text-gray-600 mb-4">{item.description || '鏆傛棤鎻忚堪'}</p>
            <div className="mb-4">
              <div className="flex items-center justify-between mb-1">
                <span className="text-sm text-gray-600">杩涘害</span>
                <span className="text-sm text-gray-600">{progress}%</span>
              </div>
              <div className="h-2 bg-gray-100 rounded-full overflow-hidden">
                <div
                  className="h-full bg-primary-500 transition-all"
                  style={{ width: `${progress}%` }}
                />
              </div>
            </div>
            <p className="text-sm text-gray-500">
              鏇存柊浜?{new Date(item.updated_at).toLocaleString('zh-CN')}
            </p>
          </div>
          <div className="flex flex-col gap-2 ml-6">
            <Button onClick={() => void handleContinue()}>
              {completed ? '鍥炲埌宸ヤ綔鍙? : '缁х画'}
            </Button>
            <Button variant="secondary" onClick={() => navigate(`/research/projects/${item.id}`)}>
              <Eye className="w-4 h-4 mr-2" />
              椤圭洰璇︽儏
            </Button>
            {completed && (
              <Link to={`/research/projects/${item.id}/achievement`}>
                <Button variant="ghost">
                  <Trophy className="w-4 h-4 mr-2" />
                  鏌ョ湅/鐢熸垚鎴愭灉鍗n                </Button>
              </Link>
            )}
          </div>
        </div>
      </CardContent>
    </Card>
  );
}
